public function handleEditor(): void
{
    global $db, $table, $errors, $message;

    if (! empty($_POST['editor_process_add']) || ! empty($_POST['editor_process_edit'])) {
        $sql_query = '';

        $item_query = $this->getQueryFromRequest();

        // set by getQueryFromRequest()
